import React, { useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import Webcam from 'react-webcam';
import axios from 'axios';

const CameraUpload = () => {
  const navigate = useNavigate();
  const webcamRef = useRef(null);

  const [showCamera, setShowCamera] = useState(false);
  const [currentFace, setCurrentFace] = useState(null);
  const [loading, setLoading] = useState(false);
  const [cameraMode, setCameraMode] = useState('user');

  const [cubeState, setCubeState] = useState({
    U: Array(9).fill('white'),
    D: Array(9).fill('yellow'),
    L: Array(9).fill('orange'),
    R: Array(9).fill('red'),
    F: Array(9).fill('green'),
    B: Array(9).fill('blue')
  });

  const faceLabels = {
    U: 'UP',
    D: 'DOWN',
    L: 'LEFT',
    R: 'RIGHT',
    F: 'FRONT',
    B: 'BACK'
  };

  const colorMap = {
    white: '#ffffff',
    yellow: '#ffff00',
    orange: '#ffa500',
    red: '#ff0000',
    green: '#00ff00',
    blue: '#0000ff'
  };

  const openCameraForFace = (face) => {
    setCurrentFace(face);
    setShowCamera(true);
  };

  const capturePhoto = async () => {
    if (!webcamRef.current) return;

    const imageSrc = webcamRef.current.getScreenshot();

    if (!imageSrc) {
      alert('Camera capture failed');
      return;
    }

    setShowCamera(false);
    setLoading(true);

    try {
      const res = await axios.post(
        'http://localhost:8000/api/detect-face/',
        {
          image: imageSrc,
          face: currentFace
        },
        {
          headers: { 'Content-Type': 'application/json' }
        }
      );

      if (res.data.success && res.data.colors?.length === 9) {
        setCubeState(prev => ({
          ...prev,
          [currentFace]: res.data.colors
        }));
      } else {
        alert(res.data.error || 'Invalid detection result');
      }
    } catch (err) {
      console.error(err);
      alert('Failed to detect face. Please try again.');
    } finally {
      setLoading(false);
      setCurrentFace(null);
    }
  };

  const switchCamera = () => {
    setCameraMode(prev =>
      prev === 'user' ? 'environment' : 'user'
    );
  };

  const cancelCamera = () => {
    setShowCamera(false);
    setCurrentFace(null);
  };

  const handleSubmit = async () => {
    setLoading(true);
    try {
      const res = await axios.post(
        'http://localhost:8000/solve/',
        cubeState,
        {
          headers: { 'Content-Type': 'application/json' }
        }
      );

      if (res.data.success) {
        navigate('/solve', {
          state: {
            solution: res.data.solution,
            cubeState
          }
        });
      } else {
        alert(res.data.error);
      }
    } catch (err) {
      console.error(err);
      alert('Failed to solve cube. Backend issue.');
    } finally {
      setLoading(false);
    }
  };

  const renderFace = (faceName, faceColors) => (
    <div className="face-wrapper">
      <h3>{faceLabels[faceName]}</h3>

      <div className="face-grid">
        {faceColors.map((color, idx) => (
          <div
            key={idx}
            className="sticker"
            style={{
              backgroundColor: colorMap[color],
              width: '50px',
              height: '50px',
              border: '1px solid black',
              margin: '2px'
            }}
          />
        ))}
      </div>

      <button
        onClick={() => openCameraForFace(faceName)}
        disabled={loading}
      >
        📷 Capture {faceLabels[faceName]}
      </button>
    </div>
  );

  return (
    <div className="camera-upload">
      <button onClick={() => navigate('/input')}>
        ← Back
      </button>

      <h2>Capture Each Face</h2>

      {showCamera && (
        <div>
          <h3>Capture {faceLabels[currentFace]}</h3>

          <Webcam
            ref={webcamRef}
            audio={false}
            screenshotFormat="image/jpeg"
            screenshotQuality={1}
            videoConstraints={{
              facingMode: cameraMode,
              width: 500,
              height: 500
            }}
          />

          <button onClick={switchCamera}>
            🔄 Switch
          </button>

          <button onClick={capturePhoto}>
            📸 Capture
          </button>

          <button onClick={cancelCamera}>
            ❌ Cancel
          </button>
        </div>
      )}

      <div>
        {Object.keys(cubeState).map(face =>
          renderFace(face, cubeState[face])
        )}
      </div>

      <button onClick={handleSubmit} disabled={loading}>
        {loading ? 'Solving...' : 'Solve Cube'}
      </button>
    </div>
  );
};

export default CameraUpload;
